-- ============================================================
-- FILE: 08_restore_from_sqlserver.sql  (v2 - Fixed for SQL Developer)
-- MUC DICH: Khoi phuc du lieu tu SQL Server sang Oracle
-- CHAY BANG: User TRASUA voi SQL Developer
-- BUOC CHUAN BI:
--   1. Connect: TRASUA / TraSua@2024
--   2. Chon Tools > Preferences > Database > SQL Developer
--      Hoac chi can bam F5 de chay ca file
-- GHI CHU: Dung GENERATED BY DEFAULT thay vi OVERRIDING SYSTEM VALUE
--          vi SQL Developer khong ho tro OVERRIDING SYSTEM VALUE
-- ============================================================

SET SERVEROUTPUT ON;

-- ============================================================
-- BUOC 0: DOI IDENTITY -> GENERATED BY DEFAULT (cho phep insert ID thu cong)
-- ============================================================
ALTER TABLE role             MODIFY id GENERATED BY DEFAULT AS IDENTITY;
ALTER TABLE customer         MODIFY id GENERATED BY DEFAULT AS IDENTITY;
ALTER TABLE branch           MODIFY id GENERATED BY DEFAULT AS IDENTITY;
ALTER TABLE account          MODIFY id GENERATED BY DEFAULT AS IDENTITY;
ALTER TABLE address_shipping MODIFY id GENERATED BY DEFAULT AS IDENTITY;

BEGIN DBMS_OUTPUT.PUT_LINE('>>> Da doi sang GENERATED BY DEFAULT xong.'); END;
/

-- ============================================================
-- BUOC 1: XOA DU LIEU CU (theo thu tu con -> cha)
-- ============================================================
-- Neu muon script khong dung lai khi bang chua co du lieu, co the dung EXCEPTION
-- Nhung o day chung ta can chac chan du lieu duoc xoa, neu xoa loi (do FK) se biet ngay
BEGIN
    EXECUTE IMMEDIATE 'DELETE FROM chat_message';
    EXECUTE IMMEDIATE 'DELETE FROM verification_code';
    EXECUTE IMMEDIATE 'DELETE FROM bill_detail_topping';
    EXECUTE IMMEDIATE 'DELETE FROM return_detail';
    EXECUTE IMMEDIATE 'DELETE FROM bill_return';
    EXECUTE IMMEDIATE 'DELETE FROM payment';
    EXECUTE IMMEDIATE 'DELETE FROM bill_detail';
    EXECUTE IMMEDIATE 'DELETE FROM bill';
    EXECUTE IMMEDIATE 'DELETE FROM cart';
    EXECUTE IMMEDIATE 'DELETE FROM branch_inventory';
    EXECUTE IMMEDIATE 'DELETE FROM address_shipping';
    EXECUTE IMMEDIATE 'DELETE FROM account';
    EXECUTE IMMEDIATE 'DELETE FROM customer';
    EXECUTE IMMEDIATE 'DELETE FROM branch';
    EXECUTE IMMEDIATE 'DELETE FROM role';
    EXECUTE IMMEDIATE 'DELETE FROM payment_method';
EXCEPTION WHEN OTHERS THEN
    DBMS_OUTPUT.PUT_LINE('Loi khi xoa du lieu cu: ' || SQLERRM);
END;
/
COMMIT;
BEGIN DBMS_OUTPUT.PUT_LINE('>>> Xoa du lieu cu xong.'); END;
/

