-- ============================================================
-- BUOC 8: RESET IDENTITY SEQUENCES ve GENERATED ALWAYS
-- va dat START WITH cao hon max ID da insert
-- ============================================================
ALTER TABLE role             MODIFY id GENERATED ALWAYS AS IDENTITY (START WITH 10  INCREMENT BY 1);
ALTER TABLE customer         MODIFY id GENERATED ALWAYS AS IDENTITY (START WITH 100 INCREMENT BY 1);
ALTER TABLE branch           MODIFY id GENERATED ALWAYS AS IDENTITY (START WITH 100 INCREMENT BY 1);
ALTER TABLE account          MODIFY id GENERATED ALWAYS AS IDENTITY (START WITH 100 INCREMENT BY 1);
ALTER TABLE address_shipping MODIFY id GENERATED ALWAYS AS IDENTITY (START WITH 100 INCREMENT BY 1);

COMMIT;

